VALUES
  ('optician-moex-00029', 'optician', 'optician-moex-114-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關甲狀腺眼症（thyroideyedisease）之敘述，下列何者錯誤？', '["屬於一種自體免疫疾病", "診斷條件必需包含甲狀腺功能亢進", "是成人單側眼球突出常見的原因", "眼外肌的病變以下直肌最為常見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:25+00:00", "source_pdf_sha1": "658858da9536", "answer_pdf_sha1": "60346d0a673e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00030', 'optician', 'optician-moex-114-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關視網膜剝離之敘述，下列何者錯誤？', '["是指感覺網膜神經層與色素上皮細胞層分離", "依照原因可分為裂孔性、牽引性和滲出性三種", "牽引性視網膜剝離是由於網膜表面纖維增生，造成視網膜牽扯，常見於糖尿病視網膜病變", "滲出性視網膜剝離是由於色素上皮細胞病變，造成滲出液堆積在網膜下，常見於早產兒視網膜病變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:25+00:00", "source_pdf_sha1": "658858da9536", "answer_pdf_sha1": "60346d0a673e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00031', 'optician', 'optician-moex-114-5e38135e', 'sub-optician-01', NULL, 'single_choice', '關於弱視的敘述，下列何者錯誤？', '["通常只需仔細檢查眼球構造可以找出異常構造", "並不一定會有瞳孔反射異常", "多數患者需使用正確的矯正眼鏡", "眼鏡度數的驗配，需要點睫狀肌麻痺藥物後的度數較正確"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:25+00:00", "source_pdf_sha1": "658858da9536", "answer_pdf_sha1": "60346d0a673e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00032', 'optician', 'optician-moex-114-5e38135e', 'sub-optician-01', NULL, 'single_choice', '對於眼球震顫病患的處置，下列何者不適當？', '["病患常會有斜眼看東西的習慣，故不適合用眼鏡來矯正屈光", "病患若沒有眼位偏斜的問題，可以考慮雙眼水平眼肌（共四條眼肌）放鬆手術，以改善視覺品質", "病患若零位點（nullpoint）的存在而有歪頭視物的情形，可以考慮雙眼水平眼肌（共四條眼肌）拉緊及 放鬆手術，以改善頭位", "眼球震顫病患間的視力差異很大，一般而言，若有零位點（nullpoint）存在者視力較佳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:25+00:00", "source_pdf_sha1": "658858da9536", "answer_pdf_sha1": "60346d0a673e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00033', 'optician', 'optician-moex-114-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關原發性隅角開放型青光眼（primaryopenangleglaucoma），下列敘述何者錯誤？', '["有較強的家族性傾向，患者的近親建議進行篩查", "主要病理特徵是小樑網狀結構的退化", "較高的眼壓與較高的視野損失有關", "每減少1毫米汞柱眼壓，青光眼進展的風險就會降低約30%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:25+00:00", "source_pdf_sha1": "658858da9536", "answer_pdf_sha1": "60346d0a673e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
