  ('optician-moex-00037', 'optician', 'optician-moex-114-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關驗光生公會，下列敘述何者錯誤？', '["由主管機關主管。但其目的事業，應受人民團體主管機關之指導、監督", "選派參加驗光生公會全國聯合會之會員代表，不以其理事、監事為限", "其區域，依現有之行政區域；在同一區域內，同級之公會以一個為限", "其理事、監事任期均為3年，其連選連任者不得超過二分之一；理事長之連任，以一次為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:25+00:00", "source_pdf_sha1": "658858da9536", "answer_pdf_sha1": "60346d0a673e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00038', 'optician', 'optician-moex-114-5e38135e', 'sub-optician-01', NULL, 'single_choice', '驗光師與驗光生替未成年人驗光配鏡時，幾歲以下應由醫師驗光？幾歲以下應於眼科醫師指導下為之？', '["10歲；15歲", "6歲；15歲", "6歲；18歲", "10歲；18歲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:25+00:00", "source_pdf_sha1": "658858da9536", "answer_pdf_sha1": "60346d0a673e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
